const VS_SRC = `#version 300 es
in vec3 aPos;
in vec3 aNormal;
in vec2 aTexCoord;
in vec3 aVertexId;

uniform mat4 uModel;
uniform mat4 uView;
uniform mat4 uProj;
uniform float uTime;

out vec3 vPos;
out vec3 vNormal;
out vec3 vVertexId;

float hash(vec2 p) { return fract(1e4 * sin(17.0 * p.x + 0.1 * p.y) * 0.3183099); }

void main() {
    vec3 pos = aPos;
    vec3 norm = aNormal;
    float type = aVertexId.x;

    if (type == 1.0) {
        float noise = hash(vec2(aVertexId.yz + uTime * 10.0));
        vec3 offset = vec3(noise - 0.5, noise * 0.5, noise - 0.5) * 0.05;
        pos += offset;
        norm += offset * 0.1; 
        norm = normalize(norm);
    }

    vec4 worldPos = uModel * vec4(pos, 1.0);
    vPos = (uView * worldPos).xyz;
    vNormal = mat3(uView * uModel) * norm;
    vVertexId = aVertexId;
    gl_Position = uProj * uView * worldPos;
}`;

const FS_SRC = `#version 300 es
precision highp float;

in vec3 vPos;
in vec3 vNormal;
in vec3 vVertexId;

uniform vec3 uColor;
uniform vec3 uLineColor;
uniform vec3 uBackground;

out vec4 outColor;

void main() {
    vec3 normal = normalize(vNormal);
    vec3 lightDir = normalize(vec3(0.5, 1.0, 0.5));
    float diff = max(dot(normal, lightDir), 0.3);

    vec3 color = uColor * diff;
    vec3 finalColor = mix(uLineColor, color, 0.15); 

    if (vVertexId.x == 1.0) {
        finalColor = vec3(1.0, 0.8, 0.2); 
    } else if (vVertexId.x == 2.0) {
        finalColor = vec3(0.0, 1.0, 1.0); 
    } else {
        if (vVertexId.y < 0.5) {
            finalColor = mix(vec3(0.8, 0.8, 0.9), finalColor, 0.5);
        }
    }

    outColor = vec4(finalColor, 1.0);
}`;

