            out[4*i+1] = m[4*i+1]*c + m[4*i+3]*-s;
            out[4*i+2] = m[4*i]*s + m[4*i+2]*c;
            out[4*i+3] = m[4*i+1]*s + m[4*i+3]*c;
        }
