function makeCylinder(r, h, segments) {
    const verts = [];
    const side = segments;
    for (let i = 0; i < side; i++) {
        const a = (i / side) * Math.PI * 2;
        const b = ((i + 1) / side) * Math.PI * 2;
        const x1 = Math.cos(a) * r, z1 = Math.sin(a) * r;
        const x2 = Math.cos(b) * r, z2 = Math.sin(b) * r;

        // Bottom Quad
        verts.push(x1, -h/2, z1, x2, -h/2, z2, 0, 1, 0, i, 0, 0);
        verts.push(x1,  h/2, z1, x2,  h/2, z2, 0, 1, 0, i, 0, 0);
        verts.push(x1,  h/2, z1, x2, -h/2, z2, 0, 1, 0, i, 0, 0);

        // Top Quad
        verts.push(x2,  h/2, z2, x1,  h/2, z1, 0, 1, 0, i, 0, 0);
        verts.push(x2, -h/2, z2, x1, -h/2, z1, 0, 1, 0, i, 0, 0);
        verts.push(x1,  h/2, z1, x2, -h/2, z2, 0, 1, 0, i, 0, 0);
    }
    return new Float32Array(verts);
}

